#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10,M=1e6+10;

int n,m,k,p[N],fx[N],fn[N],c[N],q[N],hh,tt,s[N];
vector<int> e[N];
int head[N],ver[M],nxt[M],tot,d[N],stk[N],top;
bool vis[N],ins[N];

void dfs(int x){
	stk[++top]=x;
	ins[x]=1,vis[x]=1;
	for(int y:e[x])
		if(ins[y]){
			do{
				p[++k]=stk[top--];
			}while(p[k]!=y);
			reverse(p+1,p+k+1);
			break;
		}else if(!vis[y]){
			dfs(y);
			if(k) break;
		}
	top--;
	ins[x]=0;
} 

void add(int x,int y){
	ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
	if(!c[y]) d[y]++;
}

bool Solve(){
	hh=1,tt=0;
	memset(fx,0,sizeof(fx));
	memset(fn,0x3f,sizeof(fn));
	for(int i=1;i<=k;i++)
		for(int j=head[p[i]];j;j=nxt[j])
			fx[ver[j]]=max(fx[ver[j]],i),fn[ver[j]]=min(fn[ver[j]],i),d[ver[j]]--;
	for(int i=1;i<=n;i++)
		if(!d[i] && !c[i])
			q[++tt]=i;
	while(hh<=tt){
		int x=q[hh++];
		for(int i=head[x],y;i;i=nxt[i]){
			y=ver[i];
			d[y]--;
			fx[y]=max(fx[y],fx[x]);
			fn[y]=min(fn[y],fn[x]);
			if(!d[y]) q[++tt]=y;
		}
	}
	return tt==n-k;
}

int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++){
		int u,v;
		scanf("%d%d",&u,&v);
		e[u].push_back(v);
	}
	for(int i=1;i<=n && !k;i++)
		if(!vis[i])
			dfs(i);
	if(!k){
		puts("NIE");
		return 0;
	} 
	for(int i=1;i<=k;i++)
		c[p[i]]=i;
	for(int i=1;i<=n;i++)
		for(int y:e[i])
			if(!c[i] || !c[y] || c[i]%k+1!=c[y])
				add(i,y);
	if(!Solve()){
		puts("0\n");
		return 0;
	}
	for(int i=1;i<=k;i++){
		int l=fn[p[i]],r=fx[p[i]];
		if(l<i) s[l+1]++,s[i]--;
		if(i<=r) s[1]++,s[i]--;
	}
	tot=0;
	memset(head,0,sizeof(head));
	memset(d,0,sizeof(d));
	for(int i=1;i<=n;i++)
		for(int y:e[i])
			if(!c[i] || !c[y] || c[i]%k+1!=c[y])
				add(y,i);
	Solve();
	for(int i=1;i<=k;i++){
		int l=fn[p[i]];
		if(l<=i) s[i+1]++;
	} 
	vector<int> lst;
	for(int i=1;i<=k;i++){
		s[i]+=s[i-1];
		if(!s[i]) lst.push_back(p[i]);
	}
	sort(lst.begin(),lst.end());
	printf("%d\n",lst.size());
	for(int i:lst)
		printf("%d ",i);
	return 0;
}
